#include <bits/stdc++.h>
using namespace std;
int n, q;
vector<long long> seg;
void build(int node, int l, int r, vector<long long>&a){
    if (l == r) { seg[node] = a[l]; return; }
    int m = (l + r) / 2;
    build(node*2, l, m, a); build(node*2+1, m+1, r, a);
    seg[node] = seg[node*2] + seg[node*2+1];
}
void update(int node, int l, int r, int pos, long long val){
    if (l == r) { seg[node] = val; return; }
    int m = (l + r) / 2;
    if (pos <= m) update(node*2, l, m, pos, val);
    else update(node*2+1, m+1, r, pos, val);
    seg[node] = seg[node*2] + seg[node*2+1];
}
long long query(int node, int l, int r, int ql, int qr){
    if (qr < l || r < ql) return 0;
    if (ql <= l && r <= qr) return seg[node];
    int m = (l + r) / 2;
    return query(node*2, l, m, ql, qr) + query(node*2+1, m+1, r, ql, qr);
}
int main(){
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    cin >> n >> q;
    vector<long long> a(n + 1);
    for (int i = 1; i <= n; i++) cin >> a[i];
    seg.assign(4 * (n + 1), 0);
    build(1, 1, n, a);
    while (q--){
        int op; cin >> op;
        if (op == 1) {
            int i; long long x; cin >> i >> x;
            update(1, 1, n, i, x);
        } else {
            int l, r; cin >> l >> r;
            cout << query(1, 1, n, l, r) << '\n';
        }
    }
}
